import{c as e,Q as r,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse('{"title":"Harness Engineering for Coding Agents (Martin Fowler)","description":"","frontmatter":{"url":"https://martinfowler.com/articles/harness-engineering.html","date":"2026-04-02T00:00:00.000Z","authors":"Birgitta Böckeler","source":"Martin Fowler Blog (by Birgitta Böckeler, Thoughtworks)","tags":["harness-design","feedforward","feedback","control-theory","coding-agents"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-02-martinfowler-harness-engineering-feedforward-feedback.md","filePath":"research/ai-articles/scored/2026-04-02-martinfowler-harness-engineering-feedforward-feedback.md","lastUpdated":1779901665000}'),o={name:"research/ai-articles/scored/2026-04-02-martinfowler-harness-engineering-feedforward-feedback.md"};function d(s,t,i,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="harness-engineering-for-coding-agents-martin-fowler" tabindex="-1">Harness Engineering for Coding Agents (Martin Fowler) <a class="header-anchor" href="#harness-engineering-for-coding-agents-martin-fowler" aria-label="Permalink to &quot;Harness Engineering for Coding Agents (Martin Fowler)&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://martinfowler.com/articles/harness-engineering.html" target="_blank" rel="noreferrer">https://martinfowler.com/articles/harness-engineering.html</a><br><strong>作者</strong>：Birgitta Böckeler（Thoughtworks）<br><strong>發表平台</strong>：Martin Fowler Blog<br><strong>歸檔日期</strong>：2026-05-10</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>Feedforward/Feedback 分類可直接映射到 hooks + rules</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>控制論框架應用於 harness 設計，教學價值高</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>Thoughtworks 實務來源，非嚴格實驗</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>清晰模式，實作細節留給讀者</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>適用任何 coding agent 系統</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.7/10</strong></td><td>8×0.3 + 7×0.2 + 7×0.2 + 7×0.15 + 9×0.15 = 7.70</td></tr></tbody></table><p><strong>整合決策</strong>：RULE — feedforward/feedback 分類法整合進 <code>harness-design.md</code><br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code> §元件分類<br><strong>整合狀態</strong>：待實作</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Coding agent harness 的控制論框架：<strong>Feedforward controls</strong>（引導 agent，如 architecture docs、structural tests）vs <strong>Feedback controls</strong>（感知 agent 輸出，如 linters with LLM-readable messages）。三層監管：maintainability harness、architecture fitness harness、behavior harness（最不成熟）。強調 computational（確定性）vs inferential（AI 語意）控制的分工。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><h3 id="_1-feedforward-vs-feedback-分類" tabindex="-1">1. Feedforward vs Feedback 分類 <a class="header-anchor" href="#_1-feedforward-vs-feedback-分類" aria-label="Permalink to &quot;1. Feedforward vs Feedback 分類&quot;">​</a></h3><p><strong>Feedforward Controls（引導）</strong>：</p><ul><li>Architecture Decision Records（ADRs）作為 agent 的設計約束</li><li>Structural tests（例：「所有 API handler 必須有對應 error handler」）</li><li>CLAUDE.md 中的 coding conventions</li></ul><p><strong>Feedback Controls（感知與修正）</strong>：</p><ul><li>Linters with LLM-readable error messages（不是給人看的 error，是給 AI 可理解的描述）</li><li>Unit test failure reports 格式優化</li><li>PostToolUse hooks 的輸出格式化</li></ul><blockquote><p>&quot;The quality of feedback depends on whether the AI can parse and act on it. A linter error that says &#39;line too long&#39; is worse than one that explains &#39;this line exceeds PEP-8 limits, making it harder to review in diff views.&#39;&quot;</p></blockquote><h3 id="_2-三層-harness-監管成熟度" tabindex="-1">2. 三層 Harness 監管成熟度 <a class="header-anchor" href="#_2-三層-harness-監管成熟度" aria-label="Permalink to &quot;2. 三層 Harness 監管成熟度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>層次</th><th>成熟度</th><th>範例</th></tr></thead><tbody><tr><td><strong>Maintainability</strong></td><td>✅ 成熟</td><td>lint、format、test coverage</td></tr><tr><td><strong>Architecture Fitness</strong></td><td>⚠️ 中等</td><td>dependency checks、circular import detection</td></tr><tr><td><strong>Behavior</strong></td><td>❌ 最不成熟</td><td>functional correctness、business logic validation</td></tr></tbody></table><p>Behavior harness 最難，因為需要語意理解，不能只靠 deterministic 工具。</p><h3 id="_3-computational-vs-inferential-控制" tabindex="-1">3. Computational vs Inferential 控制 <a class="header-anchor" href="#_3-computational-vs-inferential-控制" aria-label="Permalink to &quot;3. Computational vs Inferential 控制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>類型</th><th>定義</th><th>範例</th></tr></thead><tbody><tr><td><strong>Computational</strong></td><td>確定性規則</td><td>「import 必須在檔案頂部」</td></tr><tr><td><strong>Inferential</strong></td><td>AI 語意判斷</td><td>「這個函式是否符合設計意圖？」</td></tr></tbody></table><p>建議：能用 Computational 就不用 Inferential（成本、可靠性優先）。</p><hr><h2 id="對-cc-workspace-的映射" tabindex="-1">對 cc-workspace 的映射 <a class="header-anchor" href="#對-cc-workspace-的映射" aria-label="Permalink to &quot;對 cc-workspace 的映射&quot;">​</a></h2><table tabindex="0"><thead><tr><th>論文概念</th><th>cc-workspace 對應</th></tr></thead><tbody><tr><td>Feedforward controls</td><td>CLAUDE.md rules + <code>.claude/rules/*.md</code></td></tr><tr><td>Feedback controls</td><td>PostToolUse hooks（<code>pre-commit-review.sh</code>）</td></tr><tr><td>Maintainability harness</td><td><code>healthcheck.sh</code> + <code>/deep-review</code></td></tr><tr><td>Architecture fitness</td><td>目前缺乏 dependency graph checks</td></tr><tr><td>Behavior harness</td><td><code>/deep-review</code> LLM 審查（inferential）</td></tr><tr><td>LLM-readable linter messages</td><td>⚠️ 現有 lint 輸出未針對 LLM 優化</td></tr></tbody></table><p><strong>Gap</strong>：Lint 輸出未針對 LLM 優化（Computational feedback 效率不足）</p><hr><h2 id="行動建議" tabindex="-1">行動建議 <a class="header-anchor" href="#行動建議" aria-label="Permalink to &quot;行動建議&quot;">​</a></h2><ol><li>在 <code>pre-commit-review.sh</code> 中格式化 lint 輸出，加入「為什麼這是問題」的上下文</li><li>評估 Architecture Fitness harness：建立 dependency check（例：<code>scripts/check-deps.sh</code>）</li><li>在 CLAUDE.md 明確標記哪些規則是 Feedforward（靜態引導）vs Feedback（事後修正）</li></ol>',30)])])}const b=e(o,[["render",d]]);export{f as __pageData,b as default};
